// ─── Company details (edit these) ───────────────────────
const company = {
  company_name: 'Bright Studio LLC',
  company_tagline: 'Creative solutions for modern brands',
  company_address_1: '45 Innovation Drive, Suite 200',
  company_address_2: 'Austin, TX 73301, USA',
  company_email: 'user@example.com',
  company_reg: 'REG-2024-BS-7841',
  company_vat: 'US-VAT-8834201',
  bank_name: 'First National Bank',
  account_name: 'Bright Studio LLC',
  iban: 'US82 FNBK +1234567890',
  bic: 'FNBKUS33',
  payment_terms: 'Net 30',
  notes: 'Thank you for your business!',
};

// ─── Extract Stripe data ────────────────────────────────
const trigger = $('Stripe Trigger').first().json;
const session = trigger.data.object;
const lineItemsRaw = $input.first().json.data || [];

// Customer info from Stripe checkout session
const customer = session.customer_details || {};
const address = customer.address || {};

// Format line items for invoice template
const items = lineItemsRaw.map((item, i) => ({
  item_description: item.description || item.price?.product?.name || `Item ${i + 1}`,
  item_quantity: item.quantity || 1,
  item_price: ((item.amount_total || item.price?.unit_amount || 0) / 100 / (item.quantity || 1)).toFixed(2),
  item_total: ((item.amount_total || item.price?.unit_amount || 0) / 100).toFixed(2),
}));

// Generate invoice number from session date + ID
const now = new Date();
const invoiceNumber = `INV-${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}-${session.id.slice(-6).toUpperCase()}`;

// Calculate due date (Net 30)
const dueDate = new Date(now);
dueDate.setDate(dueDate.getDate() + 30);

const formatDate = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    ...company,
    client_company: customer.name || 'Customer',
    client_address_1: [address.line1, address.line2].filter(Boolean).join(', ') || '',
    client_address_2: [address.city, address.state, address.postal_code, address.country].filter(Boolean).join(', ') || '',
    client_email: customer.email || session.customer_email || '',
    invoice_number: invoiceNumber,
    invoice_date: formatDate(now),
    due_date: formatDate(dueDate),
    items: items,
    subtotal: (session.amount_subtotal / 100).toFixed(2),
    tax: ((session.total_details?.amount_tax || 0) / 100).toFixed(2),
    total: (session.amount_total / 100).toFixed(2),
    currency: (session.currency || 'usd').toUpperCase(),
    _client_email: customer.email || session.customer_email || '',
    _client_name: customer.name || 'Customer',
    _pdf_filename: invoiceNumber,
  }
}];

